<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no">
  <title>Universal Posting | Digital Sovereignty</title>
  <meta name="robots" content="noindex, nofollow">
  <link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;600&family=Oswald:wght@500;700&family=Roboto+Mono:wght@400;700&display=swap" rel="stylesheet">
  
  <style>
    :root {
      --base-dark: #1A1B1E;
      --off-black: #25262B;
      --text-main: #A6A7AB;
      --text-bright: #FFFFFF;
      --phoenix-orange: #FF6A00;
      --terminal-green: #CCFF00;
      --border-strict: 1px solid #333333;
    }
    
    * { box-sizing: border-box; margin: 0; padding: 0; border-radius: 0px!important; }
    
    body {
      background-color: var(--base-dark); color: var(--text-main);
      font-family: 'Inter', sans-serif; line-height: 1.6;
      -webkit-font-smoothing: antialiased; display: flex;
      flex-direction: column; min-height: 100vh;
    }
    
    /* --- CUSTOM SCROLLBAR PROTOCOL --- */
    ::-webkit-scrollbar {
      width: 10px;
      height: 10px;
    }
    ::-webkit-scrollbar-track {
      background: var(--base-dark);
      border: var(--border-strict);
    }
    ::-webkit-scrollbar-thumb {
      background: var(--phoenix-orange);
      border: 1px solid var(--base-dark);
    }
    ::-webkit-scrollbar-thumb:hover {
      background: var(--terminal-green);
    }
    /* --------------------------------- */

    h1, h2, h3, h4 { font-family: 'Oswald', sans-serif; text-transform: uppercase; color: var(--text-bright); letter-spacing: 1px; }
    
    .mono-data { font-family: 'Roboto Mono', monospace; font-size: 0.85rem; color: var(--terminal-green); display: block; margin-bottom: 0.5rem; }
    
    .glass-box-container { max-width: 1400px; margin: 0 auto; padding: 2rem; display: grid; grid-template-columns: 350px 1fr 300px; gap: 2rem; flex-grow: 1; }
    
    @media (max-width: 1100px) {.glass-box-container { grid-template-columns: 1fr; padding: 1rem; } }
    
    .panel { background-color: var(--off-black); border: var(--border-strict); padding: 1.5rem; }
    .panel-header { border-bottom: var(--border-strict); padding-bottom: 0.5rem; margin-bottom: 1.5rem; font-size: 1.2rem; }
    
    input, textarea, select { width: 100%; background-color: var(--base-dark); border: var(--border-strict); color: var(--text-bright); padding: 0.75rem; font-family: 'Inter', sans-serif; margin-bottom: 1.5rem; }
    input:focus, textarea:focus, select:focus { outline: none; border-color: var(--phoenix-orange); }
    
    button { background-color: var(--phoenix-orange); color: #000; border: none; padding: 1rem; font-family: 'Oswald', sans-serif; text-transform: uppercase; font-weight: 700; cursor: pointer; width: 100%; transition: background-color 0.2s; margin-bottom: 1rem; }
    button:hover { background-color: #e65f00; }
    button.secondary { background-color: transparent; color: var(--text-main); border: var(--border-strict); }
    button.secondary:hover { color: var(--text-bright); border-color: var(--text-bright); }
    
    .media-preview { width: 100%; height: 150px; background-color: var(--base-dark); border: var(--border-strict); margin-bottom: 1.5rem; display: flex; align-items: center; justify-content: center; overflow: hidden; position: relative; }
    .media-preview img { width: 100%; height: 100%; object-fit: cover; filter: grayscale(100%); transition: filter 0.3s ease; }
    .media-preview:hover img { filter: grayscale(0%); }
    
    .calendar-wrapper { display: grid; gap: 1px; background-color: #333; border: var(--border-strict); }
    .calendar-day { background-color: var(--off-black); min-height: 150px; padding: 0.5rem; min-width: 120px; }
    .day-header { font-family: 'Roboto Mono', monospace; font-size: 0.75rem; color: var(--text-main); margin-bottom: 0.5rem; border-bottom: 1px solid #333; padding-bottom: 0.25rem; }
    
    .scheduled-item { background-color: var(--base-dark); border-left: 3px solid var(--phoenix-orange); padding: 0.5rem; margin-bottom: 0.5rem; font-size: 0.8rem; cursor: pointer; transition: border-color 0.3s; position: relative; }
    .scheduled-item:hover { border-left-color: var(--text-bright); }
    .scheduled-item.ready { border-left-color: var(--terminal-green); opacity: 0.6; }
    .scheduled-item.missed { border-left-color: #FF0000; animation: pulse 2s infinite; }
    
    .delete-btn { color: #FF0000; font-weight: bold; float: right; cursor: pointer; padding: 0 4px; transition: color 0.2s; }
    .delete-btn:hover { color: var(--text-bright); }

    @keyframes pulse { 0% { opacity: 1; } 50% { opacity: 0.5; } 100% { opacity: 1; } }
    
    .group-list-item { display: flex; justify-content: space-between; align-items: center; padding: 0.5rem; border-bottom: var(--border-strict); font-size: 0.85rem; }
    
    nav { border-bottom: var(--border-strict); padding: 1rem 2rem; display: flex; justify-content: space-between; align-items: center; }
  </style>
</head>
<body>

  <div id="securityGate" style="position: fixed; top: 0; left: 0; width: 100vw; height: 100vh; background-color: var(--base-dark); z-index: 9999; display: flex; flex-direction: column; align-items: center; justify-content: center;">
    <div class="panel" style="width: 400px; text-align: center;">
      <h2 style="color: var(--phoenix-orange); margin-bottom: 1rem;">RESTRICTED ACCESS</h2>
      <span class="mono-data" style="margin-bottom: 2rem;">UNIVERSAL POSTING ENGINE v2.0</span>
      
      <input type="text" id="clientName" placeholder="OPERATIVE ALIAS (Name)" autocomplete="off">
      <input type="password" id="clientKey" placeholder="DECRYPTION KEY (Password)">
      
      <button onclick="authenticateProtocol()">INITIALIZE HANDSHAKE</button>
      <span id="authStatus" class="mono-data" style="color: #FF0000; display: none;">ACCESS DENIED.</span>
    </div>
  </div>

  <div id="header"></div>
  <script src="/header.js"></script>

  <nav>
    <h2>Universal Posting Engine</h2>
    <button id="alertBtn" style="width: auto; padding: 0.5rem 1rem; background-color: var(--terminal-green); color: #000; font-size: 0.8rem; margin: 0;" onclick="requestLocalPermissions()">ENABLE LOCAL ALERTS</button>
    <span class="mono-data" style="margin:0;">SYSTEM STATUS: <span style="color: var(--terminal-green);">ACTIVE TAB ENGINE</span></span>
  </nav>

  <div class="glass-box-container">
    <div class="panel">
      <h3 class="panel-header">Project Kickoff</h3>
      
      <label class="mono-data">SECURE TARGET</label>
      <select id="groupSelect">
        <option value="">Loading targets...</option>
      </select>
      
      <label class="mono-data">CONTENT SCRIPT</label>
      <textarea id="postContent" rows="8" placeholder="Initialize text payload here..."></textarea>
      
      <label class="mono-data">ASSET INGESTION (IMG/VID)</label>
      <input type="file" id="mediaInput" accept="image/png, image/jpeg, video/mp4, video/quicktime">
      <div class="media-preview" id="previewContainer">
        <span class="mono-data">AWAITING ASSET</span>
      </div>
      
      <label class="mono-data">EXECUTION TIMESTAMPS</label>
      <input type="datetime-local" id="scheduleTime">
      <button onclick="schedulePost()">Lock Schedule Protocol</button>
      <button class="secondary" onclick="testPublish()">Execute Manual Override</button>
    </div>

    <div class="panel" style="overflow-x: auto;">
      <h3 class="panel-header">A Glass Box Workflow: Execution Matrix</h3>
      <div class="calendar-wrapper" id="calendarGrid"></div>
    </div>

    <div class="panel">
      <h3 class="panel-header">Target Management</h3>
      <p style="font-size: 0.85rem; margin-bottom: 1rem;">Establish new operational routing vectors. Enter the Group ID or the full URL for Pages/Profiles.</p>
      
      <label class="mono-data">TARGET TYPE</label>
      <select id="newGroupType" style="margin-bottom: 1rem;">
        <option value="fb_group">Facebook Group</option>
        <option value="fb_page">Facebook Page</option>
        <option value="linkedin">LinkedIn Profile/Page</option>
      </select>

      <label class="mono-data">TARGET ALIAS</label>
      <input type="text" id="newGroupName" placeholder="e.g., Creative Startup NZ">
      
      <label class="mono-data">ROUTING IDENTIFIER / URL</label>
      <input type="text" id="newGroupId" placeholder="e.g., https://www.facebook.com/...">
      
      <button class="secondary" onclick="addGroup()">Establish Target</button>
      
      <h4 style="margin-top: 2rem; margin-bottom: 1rem; font-size: 0.9rem;">Active Targets</h4>
      <div id="activeGroupsList"></div>
    </div>
  </div>

  <div id="footer"></div>
  <script src="/footer.js"></script>

